package com.example.rest_kafka_poc.service;import com.example.rest_kafka_poc.config.Kafka_ProducerConfig;import org.apache.kafka.clients.producer.ProducerConfig;import org.apache.kafka.common.serialization.StringSerializer;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.kafka.core.KafkaTemplate;import org.springframework.kafka.core.ProducerFactory;import java.util.Map;import static org.assertj.core.api.Assertions.assertThat;@SpringBootTest(classes = Kafka_ProducerConfig.class)class KafkaProducerConfigTest {    @Autowired    ProducerFactory<String, String> producerFactory;    @Autowired    KafkaTemplate<String, String> kafkaTemplate;    @Test    void testProducerFactoryNotNull() {        assertThat(producerFactory).isNotNull();    }    @Test    void testKafkaTemplateNotNull() {        assertThat(kafkaTemplate).isNotNull();    }    @Test    void testProducerFactoryConfigContainsBootstrapServers() {        Map<String, Object> config = producerFactory.getConfigurationProperties();        assertThat(config)                .containsKey(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG)                .containsEntry(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class)                .containsEntry(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class);    }}